            padding: 2px 6px;
            border-radius: 4px;
            margin-right: 6px;
            font-weight: 500;
        }

        .tag-author {
            background: linear-gradient(135deg, #ff6b6b, #ff8787);
            color: #fff;
        }

        .tag-vip {
            background: linear-gradient(135deg, #ffa726, #ffcc02);
            color: #7c5200;
        }

        .tag-custom {
            background: linear-gradient(135deg, #4fc3f7, #29b6f6);
            color: #fff;
        }

        .comment-content {
            font-size: 15px;
            color: #333;
            line-height: 1.6;
            word-break: break-word;
            margin-bottom: 10px;
        }

        .comment-content .bq {
            width: 20px;
            height: 20px;
            vertical-align: middle;
            margin: 0 1px;
        }

        .comment-image {
            max-width: 200px;
            max-height: 200px;
            border-radius: 8px;
            margin-bottom: 10px;
            cursor: pointer;
        }

        .comment-footer {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .comment-meta {
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .comment-time {
            font-size: 12px;
            color: #999;
        }

        .comment-reply-btn {
            font-size: 12px;
            color: #666;
            cursor: pointer;
            padding: 4px 8px;
            border-radius: 4px;
            transition: background 0.2s;
        }

        .comment-reply-btn:hover {
            background: #f5f5f5;
        }

        .comment-likes {
            display: flex;
            align-items: center;
            gap: 4px;
            color: #999;
            font-size: 13px;
        }

        .comment-likes i {
            font-size: 14px;
        }

        /* 展开回复 */
        .expand-replies {
            display: flex;
            align-items: center;
            margin-top: 12px;
            padding-left: 52px;
            color: #576b95;
            font-size: 13px;
            cursor: pointer;
        }

        .expand-replies::before {
            content: '';
            width: 20px;
            height: 1px;
            background: #ddd;
            margin-right: 8px;
        }

        .expand-replies i {
            margin-left: 4px;
            font-size: 10px;
            transition: transform 0.3s;
        }

        .expand-replies.expanded i {
            transform: rotate(180deg);
        }

        /* 回复列表 */
        .reply-list {
            margin-top: 12px;
            padding-left: 52px;
            display: none;
        }

        .reply-list.show {
            display: block;
        }

        .reply-item {
            padding: 12px 0;
            border-bottom: 1px solid #f5f5f5;
        }

        .reply-item:last-child {
            border-bottom: none;
        }

        .reply-main {
            display: flex;
            gap: 10px;
        }

        .reply-avatar img {
            width: 28px;
            height: 28px;
            border-radius: 50%;
            object-fit: cover;
            background: #f0f0f0;
        }

        .reply-body {
            flex: 1;
            min-width: 0;
        }

        .reply-header {
            display: flex;
            align-items: center;
            flex-wrap: wrap;
            margin-bottom: 4px;
        }

        .reply-username {
            font-size: 13px;
            font-weight: 500;
            color: #333;
        }

        .reply-to {
            font-size: 13px;
            color: #999;
            margin: 0 4px;
        }

        .reply-to-username {
            font-size: 13px;
            color: #576b95;
        }

        .reply-content {
            font-size: 14px;
            color: #333;
            line-height: 1.5;
            margin-bottom: 6px;
        }

        .reply-content .bq {
            width: 18px;
            height: 18px;
            vertical-align: middle;
            margin: 0 1px;
        }

        .reply-footer {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .reply-time {
            font-size: 11px;
            color: #999;
        }

        .reply-likes {
            display: flex;
            align-items: center;
            gap: 3px;
            color: #999;
            font-size: 12px;
        }

        /* 默认头像 */
        .default-avatar {
            width: 40px;
            height: 40px;
            border-radius: 50%;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            display: flex;
            align-items: center;
            justify-content: center;
            color: #fff;
            font-size: 18px;
        }

        .default-avatar.small {
            width: 28px;
            height: 28px;
            font-size: 12px;
        }

        /* 底部输入栏 */
        .bottom-bar {
            position: fixed;
            bottom: 0;

            left: 0;
            right: 0;
            background: #fff;
            padding: 10px 16px;
            padding-bottom: 20px;
            display: flex;
            align-items: center;
            gap: 12px;
            border-top: 1px solid #eee;
            z-index: 100;
        }

        .input-wrapper {
            flex: 1;
            display: flex;
            align-items: center;
            background: #f5f5f5;
            border-radius: 20px;
            padding: 8px 16px;
            cursor: pointer;
        }

        .input-wrapper span {
            color: #999;
            font-size: 14px;
        }

        .bottom-actions {
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .bottom-action-btn {
            font-size: 22px;
            color: #666;
            cursor: pointer;
            transition: color 0.2s;
        }

        .bottom-action-btn:hover {
            color: #333;
        }

        /* 加载状态 */
        .loading {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 60px 20px;
            color: #999;
        }

        .loading-spinner {
            width: 32px;
            height: 32px;
            border: 3px solid #f0f0f0;
            border-top-color: #07c160;
            border-radius: 50%;
            animation: spin 0.8s linear infinite;
            margin-bottom: 12px;
        }

        @keyframes spin {
            to { transform: rotate(360deg); }
        }

        /* 空状态 */
        .empty {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 80px 20px;
            color: #999;
        }

        .empty i {
            font-size: 48px;
            margin-bottom: 16px;
            opacity: 0.3;
        }

        .empty-title {
            font-size: 15px;
            color: #666;
            margin-bottom: 8px;
        }

        .empty-desc {
            font-size: 13px;
            color: #999;
        }

        /* 没有更多 */
        .no-more {
            text-align: center;
            padding: 20px;
            color: #999;
            font-size: 13px;
        }

        /* 评论弹窗 */
        .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.5);
            z-index: 200;
            display: none;
            align-items: flex-start;
            justify-content: center;
            overflow: hidden;
            padding-top: 180px;
        }

        .modal-overlay.show {
            display: flex;
        }

        .modal-content {
            background: #fff;
            width: 90%;
            max-width: 500px;
            border-radius: 16px;
            padding: 20px;
            animation: slideDown 0.3s ease;
            transition: transform 0.3s ease;
            max-height: 80vh;
            box-shadow: 0 10px 40px rgba(0,0,0,0.2);
        }

        @keyframes slideDown {
            from {
                transform: translateY(-100%);
            }
            to {
                transform: translateY(0);
            }
        }

        .modal-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 16px;
        }

        .modal-title {
            font-size: 16px;
            font-weight: 600;
        }

        .modal-close {
            font-size: 24px;
            color: #999;
            cursor: pointer;
            padding: 4px;
        }

        .modal-textarea-wrapper {
            position: relative;
            margin-bottom: 12px;
        }

        .modal-textarea {
            width: 100%;
            min-height: 120px;
            border: 1px solid #eee;
            border-radius: 8px;
            padding: 12px;
            padding-bottom: 40px;
            font-size: 15px;
            resize: none;
            outline: none;
        }

        .modal-textarea:focus {
            border-color: #07c160;
        }

        .emoji-toggle-btn {
            position: absolute;
            bottom: 10px;
            right: 10px;
            font-size: 22px;
            color: #999;
            cursor: pointer;
            background: none;
            border: none;
            padding: 4px;
            transition: color 0.2s;
        }

        .emoji-toggle-btn:hover {
            color: #07c160;
        }

        /* 表情面板 */
        .emoji-panel {
            position: absolute;
            bottom: 45px;
            right: 0;
            background: #fff;
            border: 1px solid #eee;
            border-radius: 8px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.15);
            padding: 12px;
            width: 320px;
            max-height: 280px;
            overflow-y: auto;
            z-index: 10;
            display: none;
        }

        .emoji-panel.show {
            display: block;
        }

        .emoji-grid {
            display: grid;
            grid-template-columns: repeat(6, 1fr);
            gap: 6px;
        }

        .emoji-btn {
            padding: 8px;
            border: none;
            background: transparent;
            cursor: pointer;
            border-radius: 6px;
            transition: background 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
            aspect-ratio: 1;
        }

        .emoji-btn:hover {
            background: #f0f0f0;
        }

        .emoji-btn img {
            width: 24px;
            height: 24px;
        }

        .modal-footer {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .char-count {
            font-size: 13px;
            color: #999;
        }

        .char-count.over {
            color: #ff4d4f;
        }

        .submit-btn {
            background: #07c160;
            color: #fff;
            border: none;
            padding: 8px 24px;
            border-radius: 20px;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
        }

        .submit-btn:disabled {
            background: #ccc;
            cursor: not-allowed;
        }

        /* 图片预览 */
        .image-preview {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.9);
            z-index: 300;
            display: none;
            align-items: center;
            justify-content: center;
        }

        .image-preview.show {
            display: flex;
        }

        .image-preview img {
            max-width: 90%;
            max-height: 90%;
            border-radius: 8px;
        }

        .image-preview-close {
            position: absolute;
            top: 20px;
            right: 20px;
            font-size: 32px;
            color: #fff;
            cursor: pointer;
        }

        /* Toast */
        .toast {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            background: rgba(0, 0, 0, 0.75);
            color: #fff;
            padding: 12px 24px;
            border-radius: 8px;
            font-size: 14px;
            z-index: 400;
            display: none;
        }

        .toast.show {
            display: block;
        }

        /* 隐藏 */
        .hidden {
            display: none !important;
        }

        /* 深色模式 */
        html.dark, body.dark {
            background: #1a1a1a;
            color: #e0e0e0;
        }

        /* 确保在深色模式下整个页面都是深色背景 */
        .dark {
            background: #1a1a1a;
        }

        .dark .header {
            background: #2d2d2d;
            border-bottom-color: #3d3d3d;
        }

        .dark .header-title {
            color: #e0e0e0;
        }

        .dark .header-back {
            color: #999;
        }

        .dark .sort-btn {
            background: #3d3d3d;
            color: #999;
        }

        .dark .sort-btn:hover:not(.active) {
            background: #4d4d4d;
        }

        .dark .sort-btn.active {
            background: #07c160;
            color: #fff;
        }

        .dark .comment-btn {
            background: transparent;
            color: #07c160;
            box-shadow: none;
        }

        .dark .comment-btn:hover {
            background: transparent;
            color: #05a850;
            box-shadow: none;
        }

        .dark .comment-btn:active {
            background: transparent;
            box-shadow: none;
        }

        .dark .paragraph-quote {
            background: #2d2d2d;
            color: #aaa;
        }

        .dark .comment-list {
            background: #2d2d2d;
        }

        .dark .comment-item {
            border-bottom-color: #3d3d3d;
        }

        .dark .comment-username {
            color: #e0e0e0;
        }

        .dark .comment-content {
            color: #ccc;
        }

        .dark .comment-time {
            color: #777;
        }

        .dark .comment-likes {
            color: #777;
        }

        .dark .expand-replies {
            color: #5b9bd5;
        }

        .dark .expand-replies::before {
            background: #4d4d4d;
        }

        .dark .reply-item {
            border-bottom-color: #3d3d3d;
        }

        .dark .reply-username {
            color: #e0e0e0;
        }

        .dark .reply-content {
            color: #bbb;
        }

        .dark .reply-to-username {
            color: #5b9bd5;
        }

        .dark .reply-time,
        .dark .reply-likes {
            color: #666;
        }

        .dark .bottom-bar {
            background: #2d2d2d;
            border-top-color: #3d3d3d;
        }

        .dark .input-wrapper {
            background: #3d3d3d;
        }

        .dark .input-wrapper span {
            color: #777;
        }

        .dark .bottom-action-btn {
            color: #999;
        }

        .dark .modal-content {
            background: #2d2d2d;
        }

        .dark .modal-title {
            color: #e0e0e0;
        }

        .dark .modal-textarea {
            background: #3d3d3d;
            border-color: #4d4d4d;
            color: #e0e0e0;
        }

        .dark .modal-textarea:focus {
            border-color: #07c160;
        }

        .dark .emoji-panel {
            background: #2d2d2d;
            border-color: #4d4d4d;
        }

        .dark .emoji-btn:hover {
            background: #3d3d3d;
        }

        .dark .section-title {
            color: #e0e0e0;
        }

        .dark .loading {
            color: #777;
        }

        .dark .loading-spinner {
            border-color: #3d3d3d;
            border-top-color: #07c160;
        }

        .dark .empty {
            color: #666;
        }

        .dark .empty-title {
            color: #999;
        }

        .dark .no-more {
            color: #666;
        }

        .dark .default-avatar {
            background: linear-gradient(135deg, #4a5568 0%, #2d3748 100%);
        }

        /* 深色模式切换按钮 */
        .theme-toggle {
            width: 36px;
            height: 36px;
            border-radius: 50%;
            border: none;
            background: #f5f5f5;
            color: #666;
            font-size: 16px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            margin-left: 12px;
        }

        .theme-toggle:hover {
            background: #eee;
        }

        .dark .theme-toggle {
            background: #3d3d3d;
            color: #ffc107;
        }

        .dark .theme-toggle:hover {
            background: #4d4d4d;
        }

        /* ==================== PC端响应式优化 ==================== */
        @media (min-width: 768px) {
            body {
                background: #e8e8e8;
            }

            .dark body,
            body.dark {
                background: #121212;
            }

            .header {
                max-width: 800px;
                left: 50%;
                transform: translateX(-50%);
                border-radius: 0 0 12px 12px;
                box-shadow: 0 2px 12px rgba(0,0,0,0.08);
            }

            .main-container {
                max-width: 800px;
                margin: 0 auto;
                padding-top: 72px;
                background: transparent;
            }

            .paragraph-quote {
                margin: 16px 0;
                border-radius: 12px;
                box-shadow: 0 2px 8px rgba(0,0,0,0.04);
            }

            .hot-section {
                margin: 16px 0;
            }

            .comment-list {
                border-radius: 12px;
                box-shadow: 0 2px 8px rgba(0,0,0,0.04);
            }

            .comment-item {
                padding: 20px 24px;
            }

            .comment-item:hover {
                background: #fafafa;
            }

            .dark .comment-item:hover {
                background: #363636;
            }

            .comment-avatar img,
            .default-avatar {
                width: 48px;
                height: 48px;
                font-size: 20px;
            }

            .comment-main {
                gap: 16px;
            }

            .comment-username {
                font-size: 15px;
            }

            .comment-content {
                font-size: 15px;
                line-height: 1.7;
            }

            .comment-image {
                max-width: 300px;
                max-height: 300px;
            }

            .expand-replies {
                padding-left: 64px;
            }

            .reply-list {
                padding-left: 64px;
            }

            .reply-avatar img,
            .default-avatar.small {
                width: 32px;
                height: 32px;
                font-size: 14px;
            }

            .reply-main {
                gap: 12px;
            }

            .reply-username {
                font-size: 14px;
            }

            .reply-content {
                font-size: 14px;
                line-height: 1.6;
            }

            .bottom-bar {
                max-width: 800px;
                left: 50%;
                transform: translateX(-50%);
                border-radius: 12px 12px 0 0;
                box-shadow: 0 -2px 12px rgba(0,0,0,0.08);
            }

            .modal-content {
                max-width: 600px;
                margin: 0 auto;
                border-radius: 16px;
                margin-bottom: 20px;
            }

            /* 更多评论区域 */
            #moreSection {
                margin: 16px 0;
            }

            /* 加载状态 */
            .loading,
            .empty {
                background: #fff;
                border-radius: 12px;
                margin: 16px 0;
            }

            .dark .loading,
            .dark .empty {
                background: #2d2d2d;
            }

            .no-more {
                padding: 30px;
            }

            /* 列表容器 */
            .main-container > div[style*="margin: 0 12px"] {
                margin: 0 !important;
            }
        }

        /* 更大屏幕 */
        @media (min-width: 1200px) {
            .header,
            .main-container,
            .bottom-bar {
                max-width: 900px;
            }

            .comment-item {
                padding: 24px 32px;
            }

            .comment-avatar img,
            .default-avatar {
                width: 52px;
                height: 52px;
            }

            .expand-replies,
            .reply-list {
                padding-left: 68px;
            }
        }

        /* 超宽屏幕双栏布局（可选） */
        @media (min-width: 1400px) {
            .header,
            .main-container,
            .bottom-bar {
                max-width: 1000px;
            }
        }
    </style>
</head>
<body>
    <!-- 顶部栏 -->
    <div class="header">
        <div class="header-left">
            <span class="header-title" id="headerTitle">评论</span>
        </div>
        <div class="sort-buttons" id="sortButtons">
            <button class="comment-btn" id="commentBtn" onclick="openCommentModal()" style="display:none;">
                <i class="fas fa-pen"></i> 去评论
            </button>
            <button class="sort-btn active" id="sortByHot" onclick="sortComments('hot')">
                <i class="fas fa-fire"></i> 最热
            </button>
            <button class="sort-btn" id="sortByTime" onclick="sortComments('time')">
                <i class="fas fa-clock"></i> 最新
            </button>

            <button class="theme-toggle" id="themeToggle" onclick="toggleTheme()">
                <i class="fas fa-moon" id="themeIcon"></i>
            </button>
        </div>
    </div>

    <!-- 主容器 -->
    <div class="main-container">
        <!-- 段落内容 -->
        <div class="paragraph-quote hidden" id="paragraphQuote"></div>

        <!-- 热门评论区域（仅七猫） -->
        <div class="hot-section hidden" id="hotSection">
            <div class="section-header">
                <i class="fas fa-fire"></i>
                <span class="section-title">热门评论</span>
                <span class="section-count" id="hotCount"></span>
            </div>
            <div class="comment-list" id="hotCommentList"></div>
        </div>

        <!-- 更多评论标题（仅七猫） -->
        <div class="hot-section hidden" id="moreSection">
            <div class="section-header">
                <i class="fas fa-clock" style="color: #07c160;"></i>
                <span class="section-title">更多评论</span>
                <span class="section-count" id="moreCount"></span>
            </div>
        </div>

        <!-- 评论列表 -->
        <div style="margin: 0 12px;">
            <div class="comment-list" id="commentList"></div>
        </div>

        <!-- 加载状态 -->
        <div class="loading" id="loading">
            <div class="loading-spinner"></div>
            <span>加载中...</span>
        </div>

        <!-- 空状态 -->
        <div class="empty hidden" id="empty">
            <i class="fas fa-comment-slash"></i>
            <div class="empty-title">暂无评论</div>
            <div class="empty-desc">快来发表第一条评论吧</div>
        </div>

        <!-- 没有更多 -->
        <div class="no-more hidden" id="noMore">— 没有更多评论了 —</div>
    </div>

    <!-- 底部输入栏（仅番茄显示） -->
    <div class="bottom-bar hidden" id="bottomBar">
        <div class="input-wrapper" onclick="openCommentModal()">
            <span>趣评千万条，你也来...</span>
        </div>
        <div class="bottom-actions">
            <i class="far fa-smile bottom-action-btn" onclick="openCommentModal()"></i>
        </div>
    </div>

    <!-- 评论弹窗 -->
    <div class="modal-overlay" id="commentModal" onclick="closeCommentModal(event)">
        <div class="modal-content" onclick="event.stopPropagation()">
            <div class="modal-header">
                <span class="modal-title">发表评论</span>
                <i class="fas fa-times modal-close" onclick="closeCommentModal()"></i>
            </div>
            <div class="modal-textarea-wrapper">
