function findFirstAvailableHost(hosts) {
    // 按顺序检测，找到第一个可用的就返回
    for (var i = 0; i < hosts.length; i++) {
        var host = hosts[i];

        try {
            java.longToast("🔍 正在检测: " + host);

            var start = new Date().getTime();
            var response = java.ajax(host + "/health");
            var end = new Date().getTime();
            var time = end - start;

            // 检查是否可用
            if (String(response).indexOf("晴天") !== -1 && time <= 5000) {
                // 显示结果
                var status = "✅ 可用";
                if (time < 1000) {
                    status = "💚 优秀";
                } else if (time < 2000) {
                    status = "💛 一般";
                } else {
                    status = "🧡 较慢";
                }
                java.longToast(status + "\n主机: " + host + "\n延迟: " + time + "ms");
                return host; // 直接返回找到的主机
            }
        } catch (e) {
            // 这个主机失败，继续下一个
        }
    }

    // 所有主机都不可用
    java.longToast("❌ 没有可用的主机");
    return null;
}

function isVips(res) {
    let isVIP = '';
    let vipEndTime = res.vip_end_time;
    let formattedDate = '';

    if (vipEndTime && vipEndTime !== 0) {
        let date = new Date(vipEndTime * 1000);
        formattedDate = `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
        let currentTime = Math.floor(Date.now() / 1000);
        let remainingDays = Math.ceil((vipEndTime - currentTime) / (24 * 60 * 60));
        if (currentTime > vipEndTime) {
            isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} (已过期)`;
        } else if (remainingDays <= 7) {
            isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} 剩余${remainingDays}天`;
        } else {
            if (vipEndTime < 1912946812) {
                isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"}(${formattedDate})`;
            } else {
                isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} (永久)`;
            }
        }
    } else {
        isVIP = '您尚未开通VIP';
    }
    return isVIP;
}

